package com.example.currencyexchange;

import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Scene;
import javafx.stage.Stage;

import java.io.IOException;

public class HelloApplication extends Application {
    @Override
    public void start(Stage stage) throws IOException {
        FXMLLoader fxmlLoader = new FXMLLoader(HelloApplication.class.getResource("hello-view.fxml"));
        Scene scene = new Scene(fxmlLoader.load(), 320, 240);
        stage.setTitle("Hello!");
        stage.setScene(scene);
        stage.show();
    }
}

package com.example.currencyexchange;

import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Scene;
import javafx.stage.Stage;

import java.io.IOException;

public class HelloApplication extends Application {
    @Override
    public void start(Stage stage) throws IOException {
        // Проверяем подключение к БД при запуске
        checkDatabase();

        FXMLLoader fxmlLoader = new FXMLLoader(HelloApplication.class.getResource("hello-view.fxml"));
        Scene scene = new Scene(fxmlLoader.load(), 320, 240);
        stage.setTitle("Hello!");
        stage.setScene(scene);
        stage.show();
    }

    /**
     * Проверяет подключение к БД и выводит данные
     */
    private void checkDatabase() {
        System.out.println("\n" + "=".repeat(80));
        System.out.println("ПРОВЕРКА ПОДКЛЮЧЕНИЯ К БД");
        System.out.println("=".repeat(80));

        if (DatabaseConnection.testConnection()) {
            // Выводим данные из таблиц
            DatabaseConnection.printCurrencies();
            DatabaseConnection.printCashDesks();
            DatabaseConnection.printCashDeskStatus();
        } else {
            System.err.println("\n⚠️  ВНИМАНИЕ: Не удалось подключиться к БД!");
            System.err.println("Проверьте параметры подключения в классе DatabaseConnection:");
            System.err.println("  - URL БД");
            System.err.println("  - Имя пользователя");
            System.err.println("  - Пароль");
        }
    }
}
